#include <pthread.h>
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

/* Global shared variable */
int sum = 0;

/* Mutex for synchronizing access to shared sum variable */
pthread_mutex_t sum_mutex = PTHREAD_MUTEX_INITIALIZER;

/* Thread worker function - executes in separate thread */
void* runner(void* param) {
 int upper = *((int*)param); /* Convert void* to int* */
 int local_sum = 0;

 printf("Thread %lu: Computing sum from 1 to %d\n", 
 (unsigned long)pthread_self(), upper);

 /* Compute sum from 1 to upper */
 for (int i = 1; i <= upper; i++) {
 local_sum += i;
 }

 /* Lock mutex before updating shared variable */
 pthread_mutex_lock(&sum_mutex);
 sum = local_sum;
 pthread_mutex_unlock(&sum_mutex);

 /* Thread terminates and returns value */
 pthread_exit((void*)local_sum);
}

int main(int argc, char* argv[]) {
 if (argc != 2) {
 fprintf(stderr, "Usage: %s <positive integer>\n", argv[0]);
 return 1;
 }

 int upper = atoi(argv[1]);
 if (upper <= 0) {
 fprintf(stderr, "Please enter a positive integer\n");
 return 1;
 }

 pthread_t tid; /* Thread identifier */
 pthread_attr_t attr; /* Thread attributes */
 void* status; /* Thread return status */

 /* Initialize thread attributes to default */
 pthread_attr_init(&attr);

 printf("Main: Creating thread to sum 1 to %d\n", upper);

 /* Create a new thread */
 /* Parameters: thread id, attributes, function, function argument */
 int rc = pthread_create(&tid, &attr, runner, &upper);

 if (rc) {
 fprintf(stderr, "Error: pthread_create returned %d\n", rc);
 return 1;
 }

 /* Wait for the thread to complete (join) */
 /* Parameters: thread id, pointer to store exit status */
 rc = pthread_join(tid, &status);

 if (rc) {
 fprintf(stderr, "Error: pthread_join returned %d\n", rc);
 return 1;
 }

 printf("Main: Thread completed with status %ld\n", 
 (long)status);
 printf("Main: Sum = %d\n", sum);

 /* Clean up */
 pthread_attr_destroy(&attr);
 pthread_mutex_destroy(&sum_mutex);

 /* Exit main thread */
 pthread_exit(NULL);

 return 0;
}

// Java Thread Library - Two Methods of Thread Creation
// Method 1: Extending Thread class
// Method 2: Implementing Runnable interface

import java.util.Scanner;

/**
 * Method 1: Extending Thread class
 * Simpler but uses single inheritance
 */
class SummationThread extends Thread {
 private int upper;
 private int sum = 0;
 private boolean completed = false;

 public SummationThread(int upper) {
 this.upper = upper;
 }

 @Override
 public void run() {
 System.out.println("Thread " + getName() + ": Computing sum 1 to " + upper);
 for (int i = 1; i <= upper; i++) {
 sum += i;
 }
 completed = true;
 System.out.println("Thread " + getName() + ": Completed, sum = " + sum);
 }

 public int getSum() {
 return sum;
 }

 public boolean isCompleted() {
 return completed;
 }
}

/**
 * Method 2: Implementing Runnable interface
 * More flexible - allows class to extend other classes
 */
class SummationRunnable implements Runnable {
 private int upper;
 private int sum = 0;
 private volatile boolean completed = false;

 public SummationRunnable(int upper) {
 this.upper = upper;
 }

 @Override
 public void run() {
 System.out.println("Runnable: Computing sum 1 to " + upper);
 for (int i = 1; i <= upper; i++) {
 sum += i;
 }
 completed = true;
 System.out.println("Runnable: Completed, sum = " + sum);
 }

 public int getSum() {
 return sum;
 }

 public boolean isCompleted() {
 return completed;
 }
}

/**
 * Main class demonstrating both thread creation methods
 */
public class ThreadDemo {
 public static void main(String[] args) {
 Scanner scanner = new Scanner(System.in);
 System.out.print("Enter a positive integer: ");
 int number = scanner.nextInt();
 scanner.close();

 if (number <= 0) {
 System.out.println("Please enter a positive integer");
 return;
 }

 System.out.println("=== Method 1: Extending Thread class ===");
 method1_ExtendThread(number);

 System.out.println("\n=== Method 2: Implementing Runnable interface ===");
 method2_ImplementRunnable(number);
 }

 /**
 * Method 1: Create thread by extending Thread class
 */
 private static void method1_ExtendThread(int number) {
 // Create thread object (does NOT start it yet)
 SummationThread thread = new SummationThread(number);

 // Start the thread (calls run() method internally)
 thread.start();

 try {
 // Wait for thread to complete (similar to pthread_join)
 thread.join();
 System.out.println("Method 1 Result: " + thread.getSum());
 } catch (InterruptedException e) {
 System.out.println("Thread interrupted: " + e.getMessage());
 }
 }

 /**
 * Method 2: Create thread by implementing Runnable
 * Preferred approach (more flexible)
 */
 private static void method2_ImplementRunnable(int number) {
 // Create Runnable task
 SummationRunnable task = new SummationRunnable(number);

 // Create Thread object with Runnable (preferred method)
 Thread thread = new Thread(task);

 // Start the thread
 thread.start();

 try {
 // Wait for thread to complete
 thread.join();
 System.out.println("Method 2 Result: " + task.getSum());
 } catch (InterruptedException e) {
 System.out.println("Thread interrupted: " + e.getMessage());
 }
 }
}
